package main

import (
	"context"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

const (
	// Maximum time allowed for script execution to prevent DoS
	scriptTimeout = 5 * time.Second
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order data provided in a sandboxed environment, and returns the resulting discount amount.
// Security measures:
// 1. Script execution has a timeout to prevent DoS attacks
// 2. Order data is sandboxed in a single object to prevent prototype pollution
// 3. Order field names are validated to prevent injection attacks
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a context with timeout to prevent DoS attacks from infinite loops
	ctx, cancel := context.WithTimeout(context.Background(), scriptTimeout)
	defer cancel()

	vm := goja.New()

	// Set up interrupt channel for timeout
	// This will terminate the script if it runs too long
	go func() {
		<-ctx.Done()
		vm.Interrupt("execution timeout")
	}()

	// Create a sandboxed order object instead of injecting as globals
	// This prevents prototype pollution and other injection attacks
	orderObj := vm.NewObject()
	for key, value := range order {
		// Validate key name to prevent prototype pollution and injection
		if !isValidIdentifier(key) {
			return 0.0, fmt.Errorf("invalid order field name: %s", key)
		}
		if err := orderObj.Set(key, value); err != nil {
			return 0.0, fmt.Errorf("failed to set order field %s: %w", key, err)
		}
	}

	// Set the order object as a single global variable
	// Scripts should access order data via 'order.fieldName'
	if err := vm.Set("order", orderObj); err != nil {
		return 0.0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	discount, ok := result.Export().(float64)
	if !ok {
		// Try to convert from other numeric types (e.g., int, float32)
		switch v := result.Export().(type) {
		case int:
			discount = float64(v)
		case int32:
			discount = float64(v)
		case int64:
			discount = float64(v)
		case float32:
			discount = float64(v)
		default:
			return 0.0, fmt.Errorf("script must return a number, got %T", result.Export())
		}
	}

	return discount, nil
}

// isValidIdentifier checks if a string is a valid JavaScript identifier
// and not a dangerous property name that could lead to prototype pollution
func isValidIdentifier(name string) bool {
	if name == "" {
		return false
	}

	// Block dangerous property names that could lead to prototype pollution
	dangerousNames := map[string]bool{
		"__proto__":            true,
		"constructor":          true,
		"prototype":            true,
		"hasOwnProperty":       true,
		"isPrototypeOf":        true,
		"propertyIsEnumerable": true,
		"toLocaleString":       true,
		"toString":             true,
		"valueOf":              true,
		"__defineGetter__":     true,
		"__defineSetter__":     true,
		"__lookupGetter__":     true,
		"__lookupSetter__":     true,
	}

	if dangerousNames[name] {
		return false
	}

	// Check if first character is valid for JavaScript identifier
	first := name[0]
	if !((first >= 'a' && first <= 'z') || (first >= 'A' && first <= 'Z') || first == '_' || first == '$') {
		return false
	}

	// Check remaining characters
	for i := 1; i < len(name); i++ {
		c := name[i]
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_' || c == '$') {
			return false
		}
	}

	return true
}

