package main

import (
	"context"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

const (
	// DefaultTimeout is the maximum time a script can run
	DefaultTimeout = 5 * time.Second
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order data passed as a single 'order' object, and returns the resulting discount amount.
//
// Security improvements:
// 1. Order data is passed as a single object instead of individual globals to prevent
//    namespace pollution and prototype pollution attacks
// 2. Script execution has a timeout to prevent DoS attacks from infinite loops
// 3. Dangerous built-ins (eval, Function) are disabled to prevent arbitrary code execution
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	ctx, cancel := context.WithTimeout(context.Background(), DefaultTimeout)
	defer cancel()
	return CalculateDiscountWithContext(ctx, script, order)
}

// CalculateDiscountWithContext executes a JavaScript discount rule script with context support
func CalculateDiscountWithContext(ctx context.Context, script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Handle context cancellation and timeout
	// When context is done, interrupt the VM execution
	go func() {
		<-ctx.Done()
		vm.Interrupt(ctx.Err())
	}()

	// Disable dangerous built-ins for security
	// This prevents arbitrary code execution through eval or Function constructor
	disableDangerousBuiltins(vm)

	// SECURITY FIX: Pass order as a single object instead of individual globals
	// This prevents:
	// - Prototype pollution attacks (e.g., using __proto__ as a key)
	// - Overriding of built-in JavaScript objects (e.g., Object, Array, constructor)
	// - Namespace conflicts with reserved words
	// Scripts should access order properties via: order.total, order.customerLevel, etc.
	if err := vm.Set("order", order); err != nil {
		return 0.0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	return toFloat64(result)
}

// disableDangerousBuiltins removes access to potentially dangerous functions
// that could be exploited for arbitrary code execution
func disableDangerousBuiltins(vm *goja.Runtime) {
	global := vm.GlobalObject()

	// eval allows arbitrary code execution from strings
	_ = global.Delete("eval")

	// Function constructor can be used to create and execute arbitrary functions
	_ = global.Delete("Function")
}

// toFloat64 converts a goja value to float64
func toFloat64(result goja.Value) (float64, error) {
	if result == nil {
		return 0.0, fmt.Errorf("script returned nil")
	}

	exported := result.Export()

	switch v := exported.(type) {
	case float64:
		return v, nil
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case int64:
		return float64(v), nil
	case float32:
		return float64(v), nil
	case uint:
		return float64(v), nil
	case uint32:
		return float64(v), nil
	case uint64:
		return float64(v), nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}
}

func main() {
	// Example usage
	order := map[string]interface{}{
		"total":         100.0,
		"customerLevel": "gold",
		"items":         5,
	}

	// Discount rule script - access order properties via order object
	// Example: order.total, order.customerLevel, order.items
	script := `
		var discount = 0;
		if (order.total > 50) {
			discount = order.total * 0.1;
		}
		if (order.customerLevel === "gold") {
			discount += order.total * 0.05;
		}
		discount;
	`

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Discount: %.2f\n", discount)
}

