import (
	"context"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

const (
	// ScriptTimeout is the maximum time allowed for script execution
	ScriptTimeout = 5 * time.Second
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order data provided in a sandboxed "order" object, and returns the resulting discount amount.
//
// Security measures implemented:
// - Order data is sandboxed in an "order" object to prevent prototype pollution
// - Script execution has a timeout to prevent DoS attacks from infinite loops
// - Built-in JavaScript properties cannot be overridden by order data
//
// Scripts should access order data via "order.fieldName" (e.g., order.total, order.customerLevel)
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Handle nil order map
	if order == nil {
		order = make(map[string]interface{})
	}

	// Create a context with timeout for the VM execution to prevent DoS attacks
	ctx, cancel := context.WithTimeout(context.Background(), ScriptTimeout)
	defer cancel()

	vm := goja.New()

	// SECURITY FIX: Create a sandboxed order object instead of injecting fields as globals.
	//
	// Previously, the code did:
	//   for key, value := range order { vm.Set(key, value) }
	//
	// This was vulnerable to:
	// 1. Prototype pollution (keys like "__proto__", "constructor")
	// 2. Overriding JavaScript built-ins (keys like "toString", "valueOf", "isNaN")
	// 3. Unexpected global variable access
	//
	// Now, scripts access order data via "order.fieldName" which is safely namespaced.
	vm.Set("order", order)

	// Channel to receive the result
	type result struct {
		value goja.Value
		err   error
	}
	resultChan := make(chan result, 1)

	// Run the script in a goroutine to enable timeout handling
	go func() {
		r, err := vm.RunString(script)
		resultChan <- result{value: r, err: err}
	}()

	// Wait for either the script to complete or timeout
	select {
	case <-ctx.Done():
		// Interrupt the VM on timeout - this stops script execution
		vm.Interrupt("execution timeout")
		return 0.0, fmt.Errorf("script execution timed out after %v", ScriptTimeout)
	case res := <-resultChan:
		if res.err != nil {
			return 0.0, fmt.Errorf("script execution error: %w", res.err)
		}

		// Convert result to float64
		discount, ok := res.value.Export().(float64)
		if !ok {
			// Try to convert from other numeric types (e.g., int, float32)
			switch v := res.value.Export().(type) {
			case int:
				discount = float64(v)
			case int32:
				discount = float64(v)
			case int64:
				discount = float64(v)
			case float32:
				discount = float64(v)
			default:
				return 0.0, fmt.Errorf("script must return a number, got %T", res.value.Export())
			}
		}

		return discount, nil
	}
}

